import{j as e,p as l}from"./index-YFZcxO2M.js";import{P as o}from"./PageHero-Bdeq7tXm.js";const t="#c8161d",r=[{title:"1. المعلومات التي نجمعها",content:"نجمع المعلومات التي تقدمها مباشرةً عند إنشاء الحساب (الاسم، البريد الإلكتروني، رقم الهاتف). بيانات الاستخدام كالصفحات التي تزورها وميزات التطبيق التي تستخدمها. بيانات الشركة ومعاملاتها التي تُدخلها في المنصة. معلومات تقنية كنوع المتصفح وعنوان IP والجهاز المستخدم."},{title:"2. كيف نستخدم معلوماتك",content:"نستخدم بياناتك لتقديم وتشغيل وتحسين خدمات المنصة. إرسال الإشعارات والتحديثات المتعلقة بخدمتك. معالجة المدفوعات وإدارة اشتراكك. تقديم الدعم الفني عند الحاجة. تحليل أنماط الاستخدام لتطوير المنتج — وذلك بشكل مجمّع ومجهول الهوية فقط."},{title:"3. مشاركة البيانات",content:"لا نبيع بياناتك الشخصية لأطراف ثالثة بأي شكل. قد نشارك بياناتك مع مزودي خدمات موثوقين (مثل خدمات الاستضافة والدفع) وذلك فقط بالقدر اللازم لتشغيل الخدمة. قد نُفصح عن المعلومات إذا طُلب ذلك قانونياً أو لحماية حقوقنا أو سلامة المستخدمين."},{title:"4. أمان البيانات",content:"نستخدم تشفير TLS/SSL لحماية البيانات أثناء النقل. البيانات المخزنة مشفرة في قواعد البيانات. نُجري اختبارات أمان دورية واختراق منتظمة. يتم تقييد الوصول إلى البيانات الحساسة بصلاحيات دقيقة. لدينا خطة استجابة لحوادث الأمان معتمدة."},{title:"5. ملفات تعريف الارتباط (Cookies)",content:"نستخدم ملفات تعريف الارتباط الضرورية للحفاظ على جلسة تسجيل الدخول وضمان عمل المنصة. ملفات تحليلية مجهولة الهوية لفهم طريقة استخدام المنصة وتحسينها. يمكنك التحكم في إعدادات الكوكيز من إعدادات متصفحك، مع العلم أن إيقاف بعضها قد يؤثر على تجربة الاستخدام."},{title:"6. حقوقك",content:"يحق لك طلب الاطلاع على بياناتك الشخصية التي نحتفظ بها. تصحيح أي بيانات غير دقيقة. حذف بياناتك (الحق في النسيان) وفقاً للقانون المعمول به. تصدير بياناتك بصيغة قابلة للقراءة. إلغاء الموافقة على أي معالجة اختيارية للبيانات. للمطالبة بأي من هذه الحقوق، راسلنا على privacy@egyestate.com"},{title:"7. الاحتفاظ بالبيانات",content:"نحتفظ ببياناتك طوال فترة اشتراكك النشط. بعد إلغاء الاشتراك، تُحفظ البيانات لمدة 90 يوماً تمكّنك من تصديرها. بعد انقضاء 90 يوماً، تُحذف البيانات نهائياً من خوادمنا. يمكنك طلب حذف فوري للبيانات في أي وقت."},{title:"8. خصوصية الأطفال",content:"منصة EgyEstate موجهة للشركات والمهنيين البالغين فوق 18 عاماً. لا نجمع عن قصد أي بيانات من أفراد دون 18 عاماً. إذا اكتشفنا أن طفلاً دون 18 عاماً قدّم بيانات، سنحذفها فوراً."}];function i(){return e.jsxs(l,{children:[e.jsx(o,{tag:"قانوني",title:"سياسة الخصوصية",subtitle:"نأخذ خصوصيتك على محمل الجد. هذه السياسة تشرح بالتفصيل كيف نجمع بياناتك ونستخدمها ونحميها.",breadcrumb:[{label:"سياسة الخصوصية"}]}),e.jsxs("div",{className:"max-w-5xl mx-auto px-5 py-12",children:[e.jsx("div",{className:"bg-white rounded-3xl border border-gray-100 shadow-sm p-8 md:p-12 space-y-10",children:r.map((s,a)=>e.jsxs("div",{children:[e.jsx("h2",{className:"text-xl font-black mb-3",style:{color:t},children:s.title}),e.jsx("p",{className:"text-gray-600 leading-[2] text-base",children:s.content}),a<r.length-1&&e.jsx("div",{className:"mt-10 border-b border-gray-50"})]},a))}),e.jsx("div",{className:"mt-8 p-6 rounded-2xl border text-center",style:{background:`${t}08`,borderColor:`${t}20`},children:e.jsxs("p",{className:"text-sm text-gray-600",children:["لأي استفسارات حول الخصوصية، تواصل معنا على"," ",e.jsx("a",{href:"mailto:privacy@egyestate.com",className:"font-bold underline",style:{color:t},children:"privacy@egyestate.com"})]})})]})]})}export{i as default};
